VALUES
  ('aboriginal-c5fb3965-moex-00098', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '關於戶籍人口統計作業之月統計編報統計表之作法，下列敘述何者錯誤？', '["統計列表採用以事件登記日期為標準", "月底人口數為現有戶籍人口", "結婚、離婚及終止結婚以人數為計算單位", "雙胞胎或三胞胎以上之嬰兒有部分為死產時，將活產者列入嬰兒出生總數欄內統計，並對應列入雙胞胎 或三胞胎以上欄內統計，不計算死產人數"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "ec1e235b5965", "answer_pdf_sha1": "c1e439afad77", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0612", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00099', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '依國籍法規定，有關回復國籍者、歸化者及雙重國籍者擔任公職，下列敘述何者正確？', '["甲於民國105年回復國籍，得於民國113年擔任僑務委員會副委員長之職務", "乙於民國111年回復國籍，得於民國113年擔任僑務委員會副委員長之職務", "丙於民國105年歸化我國國籍，得於民國113年擔任僑務委員會副委員長之職務", "丁同時具美國及我國國籍，得於民國113年擔任僑務委員會副委員長之職務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "ec1e235b5965", "answer_pdf_sha1": "c1e439afad77", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0612", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00100', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '有關更正出生年月日之證明文件，或更正出生年月日證件所載歲數，下列敘述何者正確？', '["更正出生年月日所應檢附之證明文件，限於醫療機構或合格助產士出具之出生證明書", "證件僅載有歲數，但在民國前出生者，以證件所載歲數，減去發證年份，為其出生年份", "更正證件所載歲數，以國曆足歲計算", "證件僅載有歲數者，不登記出生年次"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "ec1e235b5965", "answer_pdf_sha1": "c1e439afad77", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0612", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00101', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列何種權利不能讓與？', '["著作財產權", "商標權", "親權", "債權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00102', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '關於歐陸法系與英美法系，下列敘述何者正確？', '["歐陸法系之法源以判例法為主", "英美法系不存在成文法", "屬於歐陸法系之國家不以歐洲各國為限", "屬於英美法系之國家僅有英國與美國"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00103', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', 'A控告雇主B違反勞基法，在排班輪值時未給予充足的休息時間。法院判決理由認：「勞基法第34條立法 目的在於使輪班制之勞工於換班時可獲得適當之休息時間，且此休息時間係指可使勞工獲得足以恢復原有 體力所需時間而言。輪3班制之勞工，正常工時為8小時，資方有責任注意不應使勞工於輪值大夜班後接 續出勤小夜班或輪值小夜班後接續出勤日班之情形發生。」請問上述判決理由運用了下列何種解釋方法？', '["文義解釋", "體系解釋", "歷史解釋", "目的解釋"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00104', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列關於法源之敘述，何者錯誤？', '["憲法、法律、命令為直接法源", "習慣法、法理為間接法源", "憲法法庭判決不具法源之地位", "必須客觀上有社會的慣習，還要具備主觀上法的確信，才屬於習慣法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
